import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { 
  Eye, 
  UserCheck, 
  CheckSquare, 
  Clock, 
  AlertTriangle,
  Filter,
  RefreshCw,
  Search,
  Calendar,
  Mail,
  Phone,
  Tag
} from 'lucide-react';
import { useTask } from '../../contexts/TaskContext';
import SLAStatusBadge from '../UI/SLAStatusBadge';
import PriorityBadge from '../UI/PriorityBadge';
import NotificationIndicators from '../UI/NotificationIndicators';

const RoleDashboard = ({ roleName, candidateGroup, description }) => {
  const { 
    tasks, 
    loading, 
    error, 
    stats, 
    currentRole,
    fetchTasks, 
    claimTask, 
    completeTask,
    clearError,
    updateFilters,
    filters
  } = useTask();

  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [selectedTask, setSelectedTask] = useState(null);
  const [actionLoading, setActionLoading] = useState({});

  // Fetch tasks when component mounts or role changes (without auto-refresh)
  useEffect(() => {
    if (candidateGroup && currentRole !== candidateGroup) {
      fetchTasks(candidateGroup);
    } else if (candidateGroup && currentRole === candidateGroup) {
      fetchTasks();
    }
  }, [candidateGroup, currentRole, fetchTasks]);

  // Filter tasks based on search and filters
  const filteredTasks = tasks.filter(task => {
    const matchesSearch = !searchTerm || 
      task.complaintId?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      task.customerName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      task.name?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesSLA = !filters.slaFilter || task.slaStatus === filters.slaFilter;
    const matchesPriority = !filters.priorityFilter || task.priority === filters.priorityFilter;
    const matchesState = !filters.stateFilter || task.state === filters.stateFilter;

    return matchesSearch && matchesSLA && matchesPriority && matchesState;
  });

  const handleClaimTask = async (taskId) => {
    try {
      setActionLoading(prev => ({ ...prev, [taskId]: 'claim' }));
      await claimTask(taskId, 'current-user'); // This should come from auth context
    } catch (error) {
      console.error('Failed to claim task:', error);
    } finally {
      setActionLoading(prev => ({ ...prev, [taskId]: null }));
    }
  };

  const handleCompleteTask = async (taskId) => {
    try {
      setActionLoading(prev => ({ ...prev, [taskId]: 'complete' }));
      await completeTask(taskId, {}); // Empty variables for quick complete
    } catch (error) {
      console.error('Failed to complete task:', error);
    } finally {
      setActionLoading(prev => ({ ...prev, [taskId]: null }));
    }
  };

  const handleRefresh = () => {
    fetchTasks();
  };

  const handleFilterChange = (filterType, value) => {
    updateFilters({ [filterType]: value });
  };

  const clearFilters = () => {
    updateFilters({ slaFilter: '', priorityFilter: '', stateFilter: '' });
    setSearchTerm('');
  };

  if (loading && tasks.length === 0) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{roleName} Dashboard</h1>
          <p className="text-gray-600">{description}</p>
        </div>
        <div className="flex items-center space-x-3">
          <button
            onClick={handleRefresh}
            className="flex items-center space-x-2 bg-white border border-gray-300 px-4 py-2 rounded-lg hover:bg-gray-50 transition-colors"
            disabled={loading}
          >
            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
            <span>Refresh</span>
          </button>
          <button
            onClick={() => setShowFilters(!showFilters)}
            className="flex items-center space-x-2 bg-white border border-gray-300 px-4 py-2 rounded-lg hover:bg-gray-50 transition-colors"
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
            {(filters.slaFilter || filters.priorityFilter || filters.stateFilter || searchTerm) && (
              <span className="bg-primary-100 text-primary-600 text-xs px-2 py-1 rounded-full">
                Active
              </span>
            )}
          </button>
        </div>
      </div>

      {/* Error Display */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center">
              <AlertTriangle className="w-5 h-5 text-red-600 mr-2" />
              <p className="text-red-800">{error}</p>
            </div>
            <button
              onClick={clearError}
              className="text-red-600 hover:text-red-800"
            >
              ×
            </button>
          </div>
        </div>
      )}

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Total Tasks</p>
              <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
            </div>
            <div className="bg-blue-100 rounded-full p-3">
              <Calendar className="w-6 h-6 text-blue-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">On Time</p>
              <p className="text-2xl font-bold text-success-600">{stats.onTime}</p>
            </div>
            <div className="bg-green-100 rounded-full p-3">
              <CheckSquare className="w-6 h-6 text-green-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Approaching</p>
              <p className="text-2xl font-bold text-warning-600">{stats.approaching}</p>
            </div>
            <div className="bg-yellow-100 rounded-full p-3">
              <Clock className="w-6 h-6 text-yellow-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Breached</p>
              <p className="text-2xl font-bold text-danger-600">{stats.breached}</p>
            </div>
            <div className="bg-red-100 rounded-full p-3">
              <AlertTriangle className="w-6 h-6 text-red-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Filters */}
      {showFilters && (
        <div className="bg-white rounded-lg shadow p-6 space-y-4">
          <h3 className="text-lg font-semibold text-gray-900">Filters</h3>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Search</label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                <input
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Search tasks..."
                  className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">SLA Status</label>
              <select
                value={filters.slaFilter}
                onChange={(e) => handleFilterChange('slaFilter', e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              >
                <option value="">All Status</option>
                <option value="ON_TIME">On Time</option>
                <option value="APPROACHING">Approaching</option>
                <option value="BREACHED">Breached</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Priority</label>
              <select
                value={filters.priorityFilter}
                onChange={(e) => handleFilterChange('priorityFilter', e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              >
                <option value="">All Priorities</option>
                <option value="P1">P1 - High</option>
                <option value="P2">P2 - Medium</option>
                <option value="P3">P3 - Low</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Task State</label>
              <select
                value={filters.stateFilter}
                onChange={(e) => handleFilterChange('stateFilter', e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              >
                <option value="">All States</option>
                {/* This will be populated dynamically based on available tasks */}
                {Array.from(new Set(tasks.map(t => t.state))).filter(Boolean).map(state => (
                  <option key={state} value={state}>{state}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex justify-end">
            <button
              onClick={clearFilters}
              className="px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors"
            >
              Clear Filters
            </button>
          </div>
        </div>
      )}

      {/* Tasks Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900">
            Tasks ({filteredTasks.length})
          </h2>
        </div>

        {filteredTasks.length === 0 ? (
          <div className="text-center py-12">
            <Calendar className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No tasks found</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Ticket ID
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Customer
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Task
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Priority
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    SLA Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Notifications
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Created
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredTasks.map((task) => (
                  <tr key={task.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <Tag className="w-4 h-4 text-gray-400 mr-2" />
                        <span className="text-sm font-medium text-gray-900">
                          {task.complaintId || 'N/A'}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{task.customerName || 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-900">{task.name}</div>
                      {task.assignee && (
                        <div className="text-xs text-gray-500">Assigned to: {task.assignee}</div>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <PriorityBadge priority={task.priority} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <SLAStatusBadge status={task.slaStatus} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <NotificationIndicators notification={task.notification} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {task.createdAt}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex items-center space-x-2">
                        <Link
                          to={`/task/${task.id}`}
                          className="text-primary-600 hover:text-primary-900"
                        >
                          <Eye className="w-4 h-4" />
                        </Link>

                        {!task.assignee && (
                          <button
                            onClick={() => handleClaimTask(task.id)}
                            disabled={actionLoading[task.id] === 'claim'}
                            className="text-green-600 hover:text-green-900 disabled:opacity-50"
                            title="Claim Task"
                          >
                            {actionLoading[task.id] === 'claim' ? (
                              <RefreshCw className="w-4 h-4 animate-spin" />
                            ) : (
                              <UserCheck className="w-4 h-4" />
                            )}
                          </button>
                        )}

                        {task.assignee && (
                          <button
                            onClick={() => handleCompleteTask(task.id)}
                            disabled={actionLoading[task.id] === 'complete'}
                            className="text-blue-600 hover:text-blue-900 disabled:opacity-50"
                            title="Complete Task"
                          >
                            {actionLoading[task.id] === 'complete' ? (
                              <RefreshCw className="w-4 h-4 animate-spin" />
                            ) : (
                              <CheckSquare className="w-4 h-4" />
                            )}
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default RoleDashboard;
